import{pipe,drop,every}from"@hyperjump/pact";import*as Schema from"../schema.js";import*as Instance from"../instance.js";import{getKeywordName}from"../keywords.js";import Validation from"./validation.js";const id="https://json-schema.org/keyword/items",compile=async(e,t,r)=>{var a=getKeywordName(e.dialectId,"https://json-schema.org/keyword/prefixItems"),a=await Schema.step(a,r);return[Schema.typeOf(a,"array")?Schema.length(a):0,await Validation.compile(e,t)]},interpret=([e,t],r,a,o,i)=>!Instance.typeOf(r,"array")||pipe(Instance.iter(r),drop(e),every(e=>Validation.interpret(t,e,a,o,i))),collectEvaluatedItems=(t,r,e,a)=>{if(!interpret(t,r,e,a,!0))return!1;const o=new Set;for(let e=t[0];e<Instance.length(r);e++)o.add(e);return o};export default{id:id,compile:compile,interpret:interpret,collectEvaluatedItems:collectEvaluatedItems};